def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            score = np.exp(-5 * ratio) + np.sin(5 * ratio * np.pi)
        elif 0.3 <= ratio < 0.6:
            score = 5 * (0.6 - ratio)**3 + np.log1p(ratio)
        elif 0.6 <= ratio < 0.9:
            score = np.tanh(10 * (ratio - 0.6)) + (1 - ratio)**2
        else:
            score = 1 / (1 + np.exp(-15 * (ratio - 0.9)))
        penalty = 0
        for j in range(1, 5):
            mod_val = (item * j) % capacity
            fraction = mod_val / capacity
            penalty += fraction / j
        adj_score = score + penalty
        neighbors = []
        if i > 0:
            neighbors.append(bins[i-1])
        if i < n - 1:
            neighbors.append(bins[i+1])
        neighbor_factor = 0
        for neighbor_capacity in neighbors:
            diff = abs(capacity - neighbor_capacity)
            if diff == 0:
                neighbor_factor += 0.1
            elif diff / capacity < 0.1:
                neighbor_factor += 0.05
            else:
                neighbor_factor -= 0.02
        if ratio > 0.7:
            adj_score -= 0.1 * neighbor_factor
        else:
            adj_score += 0.05 * neighbor_factor
        if int(item) % 2 == 0:
            for k in range(1, 3):
                adj_score += ((item / (k + ratio + 1)) % 1) * 0.02 * k
        else:
            for k in range(3, 6):
                adj_score -= ((item * k / (capacity + ratio + 1)) % 1) * 0.01 * k
        priorities[i] = max(adj_score, 0)
    return priorities
